Thought: I need to design a credit card system based on the provided snippet. I will implement a `CardHolder` class and a `CreditCard` base class, and then create specific card types (Visa, MasterCard, Amex) to demonstrate inheritance. I'll include methods for purchases, payments, interest calculation, and rewards. I will write the implementation to a file and then verify it with a test script.
<code>
content = """
class CardHolder:
    def __init__(self, name):
        self.name = name
        self.cards = []

    def add_card(self, card):
        self.cards.append(card)

    def get_cards(self):
        return self.cards

class CreditCard:
    def __init__(self, card_holder, card_number, card_type, initial_limit=5000):
        self.card_holder = card_holder
        # Masking card number for security
        self._card_number = card_number 
        self.card_type = card_type
        self.balance = 0
        self.rewards_points = 0
        self.credit_limit = initial_limit

    def get_masked_number(self):
        return "*" * (len(self._card_number) - 4) + self._card_number[-4:]

    def check_balance(self):
        print(f"Current balance: {self.balance}")
        return self.balance

    def make_purchase(self, amount):
        if (self.balance + amount) > self.credit_limit:
            print("Transaction denied: This transaction would exceed your credit limit.")
            return False
        else:
            self.balance += amount
            self.rewards_points += amount / 100
            print(f"Transaction approved: You have earned {amount/100} points.")
            return True

    def make_payment(self, amount):
        if amount < self.balance:
            self.balance -= amount
            print(f"Payment of {amount} accepted. New balance: {self.balance}")
        else:
            self.balance = 0
            print(f"Payment of {amount} accepted. Balance cleared.")

    def calculate_interest(self, interest_rate=0.15):
        interest = self.balance * interest_rate
        self.balance += interest
        return interest

    def check_rewards(self):
        print(f"You have {self.rewards_points} reward points.")
        return self.rewards_points

class VisaCard(CreditCard):
    def __init__(self, card_holder, card_number, initial_limit=5000):
        super().__init__(card_holder, card_number, "Visa", initial_limit)

class MasterCard(CreditCard):
    def __init__(self, card_holder, card_number, initial_limit=5000):
        super().__init__(card_holder, card_number, "MasterCard", initial_limit)

class AmexCard(CreditCard):
    def __init__(self, card_holder, card_number, initial_limit=10000):
        super().__init__(card_holder, card_number, "Amex", initial_limit)
"""
