backend_code = """
const express = require('express');
const mongoose = require('mongoose');
const multer = require('multer');
const grid = require('gridfs-stream');
const http = require('http');
const socketio = require('socket.io');
const cors = require('cors');

const app = express();
const server = http.createServer(app);
const io = socketio(server);

app.use(cors());
app.use(express.json());

mongoose.connect('mongodb://localhost:27017/mediaDB', { useNewUrlParser: true, useUnifiedTopology: true });

const gfs = grid.gridFsBucket();

const storage = multer.diskStorage({
  destination: (req, file, cb) => cb(null, 'uploads/')
});
const upload = multer({ storage });

app.post('/upload', upload.single('file'), async (req, res) => {
  try {
    const promise = new Promise((resolve, reject) => {
      const stream = mongoose.mongo.connection.db.createWriteStream({
        bucketName: 'uploads',
        filename: req.file.originalname
      });
      stream.on('error', reject);
      stream.on('finish', resolve);
      stream.end(req.file.buffer);
    });
    await promise;
    io.emit('media-added', { filename: req.file.originalname });
    res.status(201).send('Uploaded successfully');
  } catch (err) {
    res.status(500).send(err.message);
  }
});

server.listen(5000, () => console.log('Server running on port 5000'));
"""
