content = "def cum_sum_products(arr):
    def num(s) -> complex:
        if s is None:
            return 0
        try:
            if isinstance(s, str) and s.startswith(('0b', '0x', '0o')):
                return complex(int(s, 0))
            else:
                return complex(int(s))
        except ValueError:
            try:
                return complex(float(s))
            except ValueError:
                try:
                    return complex(s)
                except ValueError:
                    raise ValueError(f'Invalid value {s}')

    if not arr:
        return 0

    # Convert all values to complex numbers for consistency
    processed_arr = [num(x) for x in arr]

    n = len(processed_arr)
    total_sum = 0

    for i in range(n):
        current_product = processed_arr[i]
        for j in range(i, n):
            total_sum += current_product
            if j + 1 < n:
                current_product *= processed_arr[j+1]

    return total_sum
"
