```python
def find_none_or_empty(input_tuple, indices=None, state=None):
    import collections
    if indices is None:
        indices = []
    if state is None:
        state = collections.defaultdict(int)

    found_any = False
    if not isinstance(input_tuple, (list, tuple)):
        yield "Input should be a tuple or list."
        return

    for idx, item in enumerate(input_tuple):
        path = indices + [idx]
        if isinstance(item, (list, tuple)):
            for result in find_none_or_empty(item, path, state):
                if result == "Unsupported collection type found.":
                    yield result
                elif isinstance(result, tuple):
                    yield result
                    found_any = True
                else:
                    yield result
        elif item == "" or item is None:
            state['count'] += 1
            yield (path, state['count'])
            found_any = True
        elif isinstance(item, (set, dict)):
            yield "Unsupported collection type found."
            found_any = True

    if not found_any and not indices:
        yield "No None values or empty strings found."
```

