<code>
loader_code = "using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Reflection;

public class PluginLoader
{
    public IEnumerable<IPlugin> LoadPlugins(string path)
    {
        if (!Directory.Exists(path)) return Enumerable.Empty<IPlugin>();

        var assemblies = Directory.GetFiles(path, "*.dll").Select(Assembly.LoadFile);
        var pluginType = typeof(IPlugin);
        var plugins = new List<IPlugin>();

        foreach (var assembly in assemblies)
        {
            if (assembly == null) continue;
            var types = assembly.GetTypes().Where(t => pluginType.IsAssignableFrom(t) && !t.IsInterface && !t.IsAbstract);
            foreach (var type in types)
            {
                var plugin = Activator.CreateInstance(type) as IPlugin;
                if (plugin != null) plugins.Add(plugin);
            }
        }
        return plugins;
    }
}"
