def add_student():
    data = request.json
    name = data.get('Name')
    age = data.get('Age')
    sex = data.get('Sex')

    if not name or not isinstance(name, str) or name.strip() == '':
        return jsonify({'error': 'Invalid Name'}), 400
    try:
