def rounded_avg_custom_base(n, m, base):
    if n >= m or base < 2 or base > 10:
        return -1

    # Getting divisors for each integer [n, m] and computing their sums
    total_sum_weight = 0, 0
    for i in range(n, m + 1):
        divs = [1, i] + [x for x in range(2, int(i**0.5)+1) if i % x == 0]
        divs_for_calc = divs + [i / x for x in divs if x*x != i]
        div_count = len(divs_for_calc)
        total_sum_weight += i * div_count, div_count

    # Computing weighted mean and rounding it
    weighted_avg = round(total_sum_weight[0] / total_sum_weight[1])

    # Computing the total of the arithmetic sequence
    total_sequence = (weighted_avg * 2 + total_sum_weight[1] - 1) * total_sum_weight[1] // 2

    # Converting the total sequence to the custom base
    if base == 2:
        return bin(total_sequence)
    elif base == 8:
        return oct(total_sequence)
    elif base == 10:
        return str(total_sequence)
    else:
