content = "import time

class Server:
    def take_request(self, param):
        time.sleep(2) # simulate time delay
        return f\"Server response for {param}\" 

class ServerProxy:
    def __init__(self):
        self.cache = {}
        self.server = Server()

    def take_request(self, param):
        # Access Control
        if not isinstance(param, str):
            return \"Invalid param. It must be a string.\"

        # Cache Check
        if param not in self.cache.keys():
            print(\"Cache miss. Forwarding request to server.\")
            response = self.server.take_request(param)
            self.cache[param] = response
        else:
            print(\"Cache hit. Serving from cache.\")

        return self.cache[param]


if __name__ == \"__main__\":
    server_proxy = ServerProxy()

    print(server_proxy.take_request(\"Hello\"))
    print(server_proxy.take_request(\"Hello\"))
    print(server_proxy.take_request(1))
