1. Keyboard/Mouse can be handled via the evdev (event device) system. You can read from files in `/dev/input/event*`. Here is a basic example on how you might read keyboard input from evdev:

```c
#include <linux/input.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <stdio.h>
#include <unistd.h>

int main()
{
    int fd = open("/dev/input/event0", O_RDONLY);
    struct input_event ev;

    while (1)
    {
        read(fd, &ev, sizeof(struct input_event));

        if(ev.type == 1)
            printf("key %i state %i\n", ev.code, ev.value);
    }
    return 0;
}
```
The actual device file you read from will depend on your specific setup, and can be found by inspecting `/dev/input/`. More detailed information on using evdev can be found in section 5 of the Kernel's Input documentation (https://www.kernel.org/doc/Documentation/input/input.txt).

2. Joystick/gamepad input is typically handled via the joystick API. Here is an example of reading joystick events from a device in C:

```c
#include <fcntl.h>
#include <linux/joystick.h>
#include <stdio.h>
#include <unistd.h>

int main()
{
    int fd = open("/dev/input/js0", O_RDONLY);
    struct js_event e;

    while (1)
    {
        if (read(fd, &e, sizeof(e)) != sizeof(e))
            return -1;

        printf("type: %3u, time: %8u, number: %3u, value: %6d\n",
               e.type, e.time, e.number, e.value);
    }
    return 0;
}
```")
