```rust
fn even_characters(lst: Vec<String>) -> Vec<String> {
    let mut result = Vec::new();
    for (i, string) in lst.into_iter().enumerate() {
        let mut count = 0;
        for char in string.chars() {
            if char.to_digit(10).unwrap() % 2 == 0 {
                count += 1;
            }
        }
        result.push(format!("The amount of even characters in the {} input string is {}.", i+1, count));
    }
    result
}
```

Explanation:

