        self.hash_count = self.get_hash_count(self.size, items_count)
        self.bit_array = bitarray(self.size)
        self.bit_array.setall(0)
        self.count = 0

    def add(self, item):
        for i in range(self.hash_count):
            digest = mmh3.hash(item, i) % self.size
            self.bit_array[digest] = True
        self.count += 1

    def check(self, item):
        for i in range(self.hash_count):
            digest = mmh3.hash(item, i) % self.size
            if self.bit_array[digest] == False:
                return False
        return True

    def estimate_fp_rate(self):
        # Formula: (1 - e^(-kn/m))^k
        return (1 - math.exp(-self.hash_count * self.count / self.size)) ** self.hash_count

    @classmethod
    def get_size(cls, n, p):
        m = -(n * math.log(p)) / (math.log(2) ** 2)
        return int(m)

    @classmethod
    def get_hash_count(cls, m, n):
        k = (m / n) * math.log(2)
        return int(k)

def main():
    print("--- Bloom Filter CLI ---")
    try:
        n = int(input("Enter expected number of items: "))
        p = float(input("Enter desired false positive probability (e.g. 0.05): "))
    except ValueError:
        print("Invalid input.")
        return

    bf = BloomFilter(n, p)
    print(f"Bit array size: {bf.size}")
    print(f"Hash functions: {bf.hash_count}")

    while True:
        print("\n1. Add Item\n2. Check Item\n3. Estimate FP Rate\n4. Exit")
        choice = input("Choice: ")
        if choice == '1':
            item = input("Item to add: ")
            bf.add(item)
            print("Added.")
        elif choice == '2':
            item = input("Item to check: ")
            print(f"Present: {bf.check(item)}")
        elif choice == '3':
            print(f"Current estimated FP rate: {bf.estimate_fp_rate():.4f}")
        elif choice == '4':
            break

if __name__ == '__main__':
    main()
"
