final_answer("Here is the JavaScript function that implements the requested logic:

```javascript
function arrangeNumbers(nums) {
  // Check if the array is not empty
  if (nums.length === 0) {
    return [];
  }

  // Filter the array for even and odd numbers
  let evenNums = nums.filter(num => num % 2 === 0);
  let oddNums = nums.filter(num => num % 2 !== 0);

  // Sort the arrays in descending order (reverse numerical/alphabetical order)
  evenNums.sort((a, b) => b - a);
  oddNums.sort((a, b) => b - a);

  // Combine and return the result: even numbers first, then odd numbers
  return evenNums.concat(oddNums);
}

// Example usage:
console.log(arrangeNumbers([9, 2, 8, 4, 7])); // Output: [8, 4, 2, 9, 7]
```

This solution handles empty arrays, arrays with only one type of number (odd or even), and ensures the result is combined as [even reverse sorted] + [odd reverse sorted].")
