    transform(suffix.begin(), suffix.end(), suffix.begin(), ::tolower);

    s = prefix + s + suffix;
    string postfix = longestPalindromicPostfix(s);
    string prefixToMirror = postfix.empty() ? s : s.substr(0, s.length() - postfix.length());
    reverse(prefixToMirror.begin(), prefixToMirror.end());

    return s + prefixToMirror;
}
```")
