      if (Object.keys(items).length === 0) return null;
      const ul = document.createElement('ul');
      for (let key in items) {
        const li = document.createElement('li');
        li.textContent = key;
        const children = createList(items[key]);
        if (children) {
          li.appendChild(children);
        }
