  <title>Dynamic Nested List</title>
  <style>
    body { font-family: sans-serif; margin: 20px; }
    .controls { margin-bottom: 20px; }
    button { margin-right: 10px; cursor: pointer; }
  </style>
</head>
<body>

  <div class='controls'>
    <button onclick='addData()'>Add Data</button>
    <button onclick='deleteData()'>Delete Data</button>
    <button onclick='modifyData()'>Modify Data</button>
  </div>

  <div id='root'></div>

  <script>
    let data = {
      "Principal focal item": {
        "Supporting subordinate element": {
          "Third-order incidental component": {}
        }
      }
    };

    function createList(items) {
      if (Object.keys(items).length === 0) return null;
      const ul = document.createElement('ul');
      for (let key in items) {
        const li = document.createElement('li');
        li.textContent = key;
        const children = createList(items[key]);
        if (children) {
          li.appendChild(children);
        }
        ul.appendChild(li);
      }
      return ul;
    }

    function updateList() {
      const rootDiv = document.getElementById('root');
      rootDiv.innerHTML = '';
      const list = createList(data);
      if (list) {
        rootDiv.appendChild(list);
      }
    }

    function addData() {
      data["New focal item"] = {
        "New subordinate element": {}
      };
      updateList();
    }

    function deleteData() {
      delete data["Principal focal item"];
      updateList();
    }

    function modifyData() {
      if (data["Principal focal item"]) {
        data["Principal focal item"]["Modified subordinate element"] = {
          "New incidental component": {}
        };
        delete data["Principal focal item"]["Supporting subordinate element"];
      }
      updateList();
    }

    // Initial render
    updateList();
  </script>
</body>
</html>

