content = "class InsufficientFundsError(Exception): pass

class Account:
    def __init__(self, account_number, account_type, balance=0.0):
        self._account_number = account_number
        self._account_type = account_type
        self._balance = balance

    @property
    def balance(self):
        return self._balance

    @property
    def account_number(self):
        return self._account_number

    def deposit(self, amount):
        if amount <= 0:
            raise ValueError("Deposit amount must be positive")
        self._balance += amount
        return self._balance

    def withdraw(self, amount):
        if amount <= 0:
            raise ValueError("Withdrawal amount must be positive")
        if amount > self._balance:
            raise InsufficientFundsError("Insufficient balance")
        self._balance -= amount
        return self._balance

class SavingsAccount(Account):
    def __init__(self, account_number, balance=0.0, interest_rate=0.02):
        super().__init__(account_number, 'Savings', balance)
        self.interest_rate = interest_rate

    def apply_interest(self):
        interest = self._balance * self.interest_rate
        self.deposit(interest)

class Transaction:
    def __init__(self, transaction_type, amount, account):
        self.transaction_type = transaction_type
        self.amount = amount
        self.account = account
        self.timestamp = "2023-10-27 10:00:00" # Simplified

        if self.transaction_type.lower() == 'deposit':
            self.account.deposit(self.amount)
        elif self.transaction_type.lower() == 'withdraw':
            self.account.withdraw(self.amount)

class Client:
    def __init__(self, name, address, client_id):
        self.name = name
        self.address = address
        self.client_id = client_id
        self.accounts = []

    def add_account(self, account):
        self.accounts.append(account)

class Bank:
    def __init__(self, bank_name):
        self.bank_name = bank_name
        self.accounts = {}
        self.clients = {}

    def open_account(self, client, account_type, initial_deposit=0.0):
        acc_num = f"ACC{len(self.accounts) + 1001}"
        if account_type == 'Savings':
            account = SavingsAccount(acc_num, initial_deposit)
        else:
            account = Account(acc_num, 'Checking', initial_deposit)

        self.accounts[acc_num] = account
        client.add_account(account)
        return account

    def transfer(self, from_acc_num, to_acc_num, amount):
        if from_acc_num not in self.accounts or to_acc_num not in self.accounts:
            raise KeyError("One or both account numbers are invalid")

        from_acc = self.accounts[from_acc_num]
        to_acc = self.accounts[to_acc_num]

        from_acc.withdraw(amount)
        to_acc.deposit(amount)
        return True

    def delete_account(self, account_number):
        if account_number in self.accounts:
            del self.accounts[account_number]
            return True
        return False
