from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///test.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(80), nullable=False)
    age = db.Column(db.Integer, nullable=False)
    gender = db.Column(db.String(20), nullable=False)

with app.app_context():
    db.create_all()
    if not User.query.first():
        users = [
            User(id=1, name='Bob', age=35, gender='Male'),
            User(id=2, name='John', age=28, gender='Male'),
            User(id=3, name='Sarah', age=39, gender='Female')
        ]
        db.session.bulk_save_objects(users)
        db.session.commit()

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/users', methods=['GET'])
def get_users():
    users = User.query.all()
    return jsonify([{'id': u.id, 'name': u.name, 'age': u.age, 'gender': u.gender} for u in users])

@app.route('/add', methods=['POST'])
def add():
    data = request.form
    new_user = User(name=data['name'], age=int(data['age']), gender=data['gender'])
    db.session.add(new_user)
    db.session.commit()
    return jsonify({'status': 'success'})

@app.route('/update', methods=['POST'])
def update():
    data = request.form
    user = User.query.get(data['id'])
    if user:
        user.name = data['name']
        user.age = int(data['age'])
        user.gender = data['gender']
        db.session.commit()
        return jsonify({'status': 'success'})
    return jsonify({'status': 'error'}), 404

if __name__ == '__main__':
