            $.get('/users', function(data) {
                let rows = '';
                data.forEach(u => {
                    rows += `<tr>
                        <td>${u.id}</td>
                        <td><input type="text" id="name-${u.id}" value="${u.name}"></td>
                        <td><input type="number" id="age-${u.id}" value="${u.age}"></td>
                        <td><input type="text" id="gender-${u.id}" value="${u.gender}"></td>
                        <td><button onclick="updateUser(${u.id})">Update</button></td>
                    </tr>`;
                });
                $('#userTable tbody').html(rows);
            });
        }

        function addUser() {
            const name = $('#newName').val();
            const age = $('#newAge').val();
            const gender = $('#newGender').val();
            $.post('/add', {name, age, gender}, function() {
                fetchUsers();
                $('#newName, #newAge, #newGender').val('');
            });
        }

        function updateUser(id) {
            const name = $('#name-' + id).val();
            const age = $('#age-' + id).val();
            const gender = $('#gender-' + id).val();
            $.post('/update', {id, name, age, gender}, function() {
                alert('Updated successfully!');
                fetchUsers();
            });
        }

        function sortTable(n) {
            var table = document.getElementById("userTable");
            var rows, switching, i, x, y, shouldSwitch, dir, switchcount = 0;
            switching = true;
            dir = "asc";
            while (switching) {
                switching = false;
                rows = table.rows;
                for (i = 1; i < (rows.length - 1); i++) {
                    shouldSwitch = false;
                    x = rows[i].getElementsByTagName("TD")[n];
                    y = rows[i + 1].getElementsByTagName("TD")[n];
                    let xVal = x.innerText || x.firstChild.value;
                    let yVal = y.innerText || y.firstChild.value;
                    if (dir == "asc") {
                        if (xVal > yVal) { shouldSwitch = true; break; }
                    } else if (dir == "desc") {
                        if (xVal < yVal) { shouldSwitch = true; break; }
                    }
                }
                if (shouldSwitch) {
                    rows[i].parentNode.insertBefore(rows[i + 1], rows[i]);
                    switching = true;
                    switchcount ++;
                }
                if (switchcount == 0 && dir == "asc") {
                    dir = "desc";
                    switching = true;
                }
            }
        }

        $(document).ready(fetchUsers);
    </script>
