component_content = "import React, { Component } from 'react';
import { connect } from 'react-redux';
import { Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Paper, TablePagination, TableSortLabel, Typography } from '@material-ui/core';
import { fetchData } from './actions';

class DataTable extends Component {
  state = {
    order: 'asc',
    orderBy: 'id',
    page: 0,
    rowsPerPage: 10,
  };

  componentDidMount() {
    this.props.fetchData();
  }

  handleRequestSort(property) {
    const isAsc = this.state.orderBy === property && this.state.order === 'asc';
    this.setState({
      order: isAsc ? 'desc' : 'asc',
      orderBy: property,
    });
  }

  handleChangePage(event, newPage) {
    this.setState({ page: newPage });
  }

  handleChangeRowsPerPage(event) {
    this.setState({ rowsPerPage: parseInt(event.target.value, 10), page: 0 });
  }

  renderNestedData(data) {
    if (typeof data === 'object' && data !== null) {
      return (
        <div style={{ marginLeft: '10px', fontSize: '0.8em', borderLeft: '1px solid #ccc', paddingLeft: '5px' }}>
          {Object.entries(data).map(([key, val]) => (
            <div key={key}>
              <strong>{key}:</strong> {typeof val === 'object' ? this.renderNestedData(val) : val}
            </div>
          ))}
        </div>
      );
    }
    return data;
  }

  render() {
    const { data, loading, error } = this.props;//n    if (loading) return <Typography>Loading...</Typography>;
    if (error) return <Typography color='error'>Error: {error}</Typography>;
    if (!data || data.length === 0) return <Typography>No data available</Typography>;

    const keys = Object.keys(data[0]);
    const sortedData = [...data].sort((a, b) => {
      const isAsc = this.state.order === 'asc';
      if (a[this.state.orderBy] < b[this.state.orderBy]) return isAsc ? -1 : 1;
      if (a[this.state.orderBy] > b[this.state.orderBy]) return isAsc ? 1 : -1;
      return 0;
    });

    return (
      <Paper>
        <TableContainer>
          <Table component='div' style={{ width: '100%', overflowX: 'auto' }}>
            <TableHead>
              <TableRow>
                {keys.map(key => (
                  <TableCell
                    key={key}
                    sortDirection={this.state.orderBy === key ? this.state.order : false}
                  >
                    <TableSortLabel
                      active={this.state.orderBy === key}
                      direction={this.state.orderBy === key ? this.state.order : 'asc'}
                      onClick={() => this.handleRequestSort(key)}
                    >
                      {key}
                    </TableSortLabel>
                  </TableCell
                ))}
              </TableRow>
            </TableHead>
            <TableBody>
              {sortedData
                .slice(this.state.page * this.state.rowsPerPage, this.state.page * this.state.rowsPerPage + this.state.rowsPerPage)
                .map((row, idx) => (
                  <TableRow key={idx}>
                    {keys.map(key => (
                      <TableCell key={key}>
                        {this.renderNestedData(row[key])}
                      </TableCell>
                    ))}
                  </TableRow>
                ))}
            </TableBody>
          </Table>
        </TableContainer>
        <TablePagination
          rowsPerPageOptions={[5, 10, 25]}
          component='div'
          count={data.length}
          rowsPerPage={this.state.rowsPerPage}
          page={this.state.page}
          onPageChange={this.handleChangePage}
          onRowsPerPageChange={this.handleChangeRowsPerPage}
        />
      </Paper>
    );
  }
}

const mapStateToProps = state => ({ data: state.data, loading: state.loading, error: state.error });
const mapDispatchToProps = { fetchData };
export default connect(mapStateToProps, mapDispatchToProps)(DataTable);"
