        return None
    report = {'total_keys': 0, 'data_types_count': {}, 'empty_values': 0}
    for key, value in d.items():
        report['total_keys'] += 1
        v_type = type(value).__name__
        report['data_types_count'][v_type] = report['data_types_count'].get(v_type, 0) + 1
