                    return intList.Zip(intList.Skip(1), (a, b) => a < b).All(x => x) || intList.Zip(intList.Skip(1), (a, b) => a > b).All(x => x);
                }
                else
                {
                    return intList.Zip(intList.Skip(1), (a, b) => a <= b).All(x => x) || intList.Zip(intList.Skip(1), (a, b) => a >= b).All(x => x);
                }
            }
        }
        catch (Exception)
        {
            Console.WriteLine("Input value is not iterable");
            return false;
        }
    }

    public static void Main()
    {
        Console.WriteLine(IsMonotonic(new List<object> { 1, 2, 4, 20 }));  // True
        Console.WriteLine(IsMonotonic(new List<object> { 1, 20, 4, 10 }));  // False
        Console.WriteLine(IsMonotonic(new List<object> { 4, 1, 1, 0, -10 }, true));  // False
        Console.WriteLine(IsMonotonic(new List<object> { 1, 1, 1, 1 }, false));  // True
        Console.WriteLine(IsMonotonic(new List<object> { new List<object>{1, 2, 3}, new List<object>{5, 6, 7}, new List<object>{8, 9, 10} }));  // True
        Console.WriteLine(IsMonotonic(new List<object> { new List<object>{5, 6, 5}, new List<object>{2, 3, 4} }, true));  // False
    }
}
