content = "import collections

class TextEditor:
    def __init__(self, initial_text=""):
        self.text = initial_text
        self.undo_stack = []

    def insert(self, index, text):
        self._save_state()
        self.text = self.text[:index] + text + self.text[index:]

    def delete(self, index, length):
        self._save_state()
        self.text = self.text[:index] + self.text[index + length:]

    def search(self, query):
        return self.text.find(query)

    def undo(self):
        if self.undo_stack:
            self.text = self.undo_stack.pop()

    def _save_state(self):
        self.undo_stack.append(self.text)

if __name__ == '__main__':
    editor = TextEditor("Hello World")
    editor.insert(6, "Beautiful ")
    print(f"After insert: {editor.text}")
    editor.delete(6, 10)
    print(f"After delete: {editor.text}")
    editor.undo()
    print(f"After undo: {editor.text}")
    print(f"Search 'World': {editor.search('World')}")
"
