from pymongo.errors import ConnectionFailure, OperationFailure

class MongoDBInterface:
    def __init__(self, host='localhost', port=27017, db_name='pattern_db'):
        try:
            self.client = MongoClient(host, port, serverSelectionTimeoutMS=5000)
            self.db = self.client[db_name]
            # Trigger a connection check
            self.client.admin.command('ping')
            print('Connected to MongoDB successfully')
        except ConnectionFailure:
            print('Failed to connect to MongoDB')
            raise

    def insert_data(self, collection_name, data):
        collection = self.db[collection_name]
        try:
            if isinstance(data, list):
                result = collection.insert_many(data)
            else:
                result = collection.insert_one(data)
            print(f'Inserted data into {collection_name}')
            return result
        except OperationFailure as e:
            print(f'Failed to insert data: {str(e)}')
            return None

    def retrieve_data(self, collection_name, query=None, projection=None):
        collection = self.db[collection_name]
        try:
            cursor = collection.find(query or {}, projection)
            return list(cursor)
        except OperationFailure as e:
            print(f'Error retrieving data: {str(e)}')
            return []
"
