        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static int lcm(int a, int b) {
        if (a == 0 || b == 0) return 0;
        int gcd = gcd(a, b);
        return Math.abs(a / gcd * b);
    }

    public static int[] pairLCM(int[] inputArray) {
        if (inputArray == null || inputArray.length == 0) return new int[0];
        for (int i = 0; i < inputArray.length; i++) {
            if (inputArray[i] <= 0) {
                throw new IllegalArgumentException("Input array should contain only positive integers.");
            }
        }
        int len = inputArray.length;
        int[] outputArray = new int[(len + 1) / 2];
        for (int i = 0; i < len / 2; i++) {
            outputArray[i] = lcm(inputArray[2 * i], inputArray[2 * i + 1]);
        }
